import{_ as e,o as a,c as i,a2 as s}from"./chunks/framework.jWxB9oXr.js";const g=JSON.parse('{"title":"Environment Variables","description":"Complete reference for all SILVERY_ environment variables — verification, debugging, diagnostics, and layout configuration.","frontmatter":{"title":"Environment Variables","description":"Complete reference for all SILVERY_ environment variables — verification, debugging, diagnostics, and layout configuration.","head":[["meta",{"property":"og:title","content":"Environment Variables"}],["meta",{"property":"og:description","content":"Complete reference for all SILVERY_ environment variables — verification, debugging, diagnostics, and layout configuration."}],["meta",{"property":"og:url","content":"https://silvery.dev/reference/environment-variables.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/reference/environment-variables.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://silvery.dev/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Environment Variables\\",\\"item\\":\\"https://silvery.dev/reference/environment-variables\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Environment Variables\\",\\"description\\":\\"Complete reference for all SILVERY_ environment variables — verification, debugging, diagnostics, and layout configuration.\\",\\"url\\":\\"https://silvery.dev/reference/environment-variables.html\\",\\"dateModified\\":\\"2026-04-10T20:45:43.000Z\\",\\"datePublished\\":\\"2026-04-10T20:45:43.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"reference/environment-variables.md","filePath":"reference/environment-variables.md","lastUpdated":1775853943000}'),n={name:"reference/environment-variables.md"};function r(d,t,l,o,h,p){return a(),i("div",null,[...t[0]||(t[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /reference/environment-variables.md for this page in Markdown format</div><h1 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h1><p>Silvery reads <code>SILVERY_*</code> environment variables at startup for verification, debugging, diagnostics, and configuration. None are required for normal operation.</p><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>These variables enable automatic correctness checking. They add overhead and are intended for development and CI, not production.</p><h3 id="silvery-strict" tabindex="-1">SILVERY_STRICT <a class="header-anchor" href="#silvery-strict" aria-label="Permalink to &quot;SILVERY_STRICT&quot;">​</a></h3><p>Buffer-level verification that <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> matches a fresh <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code>, <code>true</code> to enable; <code>0</code>, <code>false</code>, or unset to disable</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>After every frame, re-renders the entire tree from scratch and compares cell-by-cell against the incremental result. Throws <code>IncrementalRenderMismatchError</code> on any difference. This is the primary invariant check for the <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> pipeline.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STRICT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-strict-terminal" tabindex="-1">SILVERY_STRICT_TERMINAL <a class="header-anchor" href="#silvery-strict-terminal" aria-label="Permalink to &quot;SILVERY_STRICT_TERMINAL&quot;">​</a></h3><p>ANSI-level verification via terminal emulator backends. Replays the ANSI output through one or more terminal emulators and compares the resulting screen against the buffer.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>vt100</code>, <code>xterm</code>, <code>ghostty</code>, <code>all</code>, or a comma-separated list (e.g. <code>vt100,xterm</code>)</td></tr><tr><td><strong>Default</strong></td><td>Disabled (empty string)</td></tr></tbody></table><ul><li><code>vt100</code> — fast internal parser (stateless)</li><li><code>xterm</code> — xterm.js emulator (stateful, higher fidelity)</li><li><code>ghostty</code> — Ghostty terminal emulator (stateful)</li><li><code>all</code> — equivalent to <code>vt100,xterm,ghostty</code></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STRICT_TERMINAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">vt100</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STRICT_TERMINAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">all</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-strict-accumulate" tabindex="-1">SILVERY_STRICT_ACCUMULATE <a class="header-anchor" href="#silvery-strict-accumulate" aria-label="Permalink to &quot;SILVERY_STRICT_ACCUMULATE&quot;">​</a></h3><p>Replays ALL frames from the start on every <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> to catch compounding errors. O(N^2) cost.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code>, <code>true</code> to enable; <code>0</code>, <code>false</code>, or unset to disable</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Separate from <code>SILVERY_STRICT</code> — opt-in only because of the quadratic cost. Catches errors that only manifest after many incremental renders accumulate small drifts.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STRICT_ACCUMULATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-stability-skip-lines" tabindex="-1">SILVERY_STABILITY_SKIP_LINES <a class="header-anchor" href="#silvery-stability-skip-lines" aria-label="Permalink to &quot;SILVERY_STABILITY_SKIP_LINES&quot;">​</a></h3><p>Skip specific lines during stability checks in <code>withDiagnostics()</code>. Useful when certain lines contain non-deterministic content (timestamps, spinners).</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>Comma-separated line numbers (0-indexed), e.g. <code>0,5,12</code></td></tr><tr><td><strong>Default</strong></td><td>None</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_STABILITY_SKIP_LINES</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0,23</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre></div><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h2><p>These variables produce diagnostic output to help trace rendering issues.</p><h3 id="silvery-instrument" tabindex="-1">SILVERY_INSTRUMENT <a class="header-anchor" href="#silvery-instrument" aria-label="Permalink to &quot;SILVERY_INSTRUMENT&quot;">​</a></h3><p>Enable stats collection for the <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> pipeline. Exposes skip/<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> counts, cascade depth, and scroll tier decisions.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code>, <code>true</code> to enable</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Stats are available via <code>DEBUG=silvery:content</code> log output and programmatically on <code>globalThis.__silvery_content_detail</code>. Automatically enabled when <code>SILVERY_STRICT</code> is active.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_INSTRUMENT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">silvery:content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DEBUG_LOG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/silvery.log</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-cell-debug" tabindex="-1">SILVERY_CELL_DEBUG <a class="header-anchor" href="#silvery-cell-debug" aria-label="Permalink to &quot;SILVERY_CELL_DEBUG&quot;">​</a></h3><p>Trace which nodes cover a specific cell position. Produces per-cell diagnostic output showing the <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> cascade for that coordinate.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>col,row</code> (e.g. <code>77,85</code>)</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Requires <code>DEBUG=silvery:content:cell</code> and <code>DEBUG_LOG</code> to see output.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_CELL_DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">77,85</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DEBUG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">silvery:content:cell</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DEBUG_LOG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/silvery.log</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-capture-output" tabindex="-1">SILVERY_CAPTURE_OUTPUT <a class="header-anchor" href="#silvery-capture-output" aria-label="Permalink to &quot;SILVERY_CAPTURE_OUTPUT&quot;">​</a></h3><p>Capture the ANSI output written to the terminal after each frame. Appends frame-delimited output to the specified file path.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>File path (e.g. <code>/tmp/silvery-output.ansi</code>)</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Each frame is prefixed with a header showing the frame number and byte count.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_CAPTURE_OUTPUT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/silvery-output.ansi</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-capture-raw" tabindex="-1">SILVERY_CAPTURE_RAW <a class="header-anchor" href="#silvery-capture-raw" aria-label="Permalink to &quot;SILVERY_CAPTURE_RAW&quot;">​</a></h3><p>Capture raw ANSI output from the runtime diff phase to a fixed file path (<code>/tmp/silvery-runtime-raw.ansi</code>).</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>Any truthy value (e.g. <code>1</code>)</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Unlike <code>SILVERY_CAPTURE_OUTPUT</code> (which captures scheduler output with frame headers), this captures the raw diff patches from the runtime layer.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_CAPTURE_RAW</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-dev" tabindex="-1">SILVERY_DEV <a class="header-anchor" href="#silvery-dev" aria-label="Permalink to &quot;SILVERY_DEV&quot;">​</a></h3><p>Enable the dev inspector for live tree inspection and diagnostics.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code>, <code>true</code> to enable</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_DEV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-dev-log" tabindex="-1">SILVERY_DEV_LOG <a class="header-anchor" href="#silvery-dev-log" aria-label="Permalink to &quot;SILVERY_DEV_LOG&quot;">​</a></h3><p>Set the log file path for the dev inspector. Only meaningful when <code>SILVERY_DEV</code> is enabled.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>File path (e.g. <code>/tmp/silvery-dev.log</code>)</td></tr><tr><td><strong>Default</strong></td><td>None (logs to default output)</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_DEV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SILVERY_DEV_LOG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/silvery-dev.log</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>These variables change runtime behavior.</p><h3 id="silvery-engine" tabindex="-1">SILVERY_ENGINE <a class="header-anchor" href="#silvery-engine" aria-label="Permalink to &quot;SILVERY_ENGINE&quot;">​</a></h3><p>Select the layout engine. Silvery ships with two layout backends.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>flexily</code> (default), <code>yoga</code></td></tr><tr><td><strong>Default</strong></td><td><code>flexily</code></td></tr></tbody></table><p><a href="https://beorn.codes/flexily" class="hover-link" data-tooltip="Pure JavaScript flexbox layout engine — powers Silvery&#39;s layout system" target="_blank" rel="noopener">Flexily</a> is a zero-allocation <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible flexbox engine written in TypeScript. <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> is the original C++ engine via <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>. Both produce identical layouts for supported properties.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_ENGINE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">yoga</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-sync-update" tabindex="-1">SILVERY_SYNC_UPDATE <a class="header-anchor" href="#silvery-sync-update" aria-label="Permalink to &quot;SILVERY_SYNC_UPDATE&quot;">​</a></h3><p>Force synchronous terminal output updates by wrapping output in DCS <a href="https://terminfo.dev/modes/decset-2026-synchronized-output" class="hover-link" data-tooltip="DEC 2026 protocol for atomic screen updates — prevents visual tearing" target="_blank" rel="noopener">synchronized update</a> sequences.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code>, <code>true</code> to enable</td></tr><tr><td><strong>Default</strong></td><td>Disabled</td></tr></tbody></table><p>Prevents tearing on terminals that support <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="DEC mode 2026 — wraps frame emission so the terminal paints atomically. Prevents tearing in tmux, Zellij, and other multiplexers.">synchronized output</a>. Currently disabled by default due to a Ghostty rendering bug with incremental diff output.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_SYNC_UPDATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-bg-conflict" tabindex="-1">SILVERY_BG_CONFLICT <a class="header-anchor" href="#silvery-bg-conflict" aria-label="Permalink to &quot;SILVERY_BG_CONFLICT&quot;">​</a></h3><p>Control how background color conflicts are handled when a <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> node has both an explicit background and an inherited background from an ancestor <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>throw</code> (default), <code>warn</code>, <code>ignore</code></td></tr><tr><td><strong>Default</strong></td><td><code>throw</code></td></tr></tbody></table><ul><li><code>throw</code> — fail fast on programming errors (recommended)</li><li><code>warn</code> — log a warning but continue</li><li><code>ignore</code> — silently ignore conflicts</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_BG_CONFLICT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">warn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-no-incremental" tabindex="-1">SILVERY_NO_INCREMENTAL <a class="header-anchor" href="#silvery-no-incremental" aria-label="Permalink to &quot;SILVERY_NO_INCREMENTAL&quot;">​</a></h3><p>Disable <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> entirely. Every frame performs a full fresh <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>1</code> to disable <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span></td></tr><tr><td><strong>Default</strong></td><td>Disabled (<span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> is on)</td></tr></tbody></table><p>Useful for isolating whether a bug is in the <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> logic or in the base pipeline.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_NO_INCREMENTAL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-no-text-cache" tabindex="-1">SILVERY_NO_TEXT_CACHE <a class="header-anchor" href="#silvery-no-text-cache" aria-label="Permalink to &quot;SILVERY_NO_TEXT_CACHE&quot;">​</a></h3><p>Disable the text measurement cache. Forces re-measurement of every text node on every <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>Any truthy value (e.g. <code>1</code>)</td></tr><tr><td><strong>Default</strong></td><td>Disabled (cache is on)</td></tr></tbody></table><p>Useful for benchmarking the cache&#39;s performance impact or debugging stale measurement issues.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_NO_TEXT_CACHE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span></span></code></pre></div><h3 id="silvery-nontty" tabindex="-1">SILVERY_NONTTY <a class="header-anchor" href="#silvery-nontty" aria-label="Permalink to &quot;SILVERY_NONTTY&quot;">​</a></h3><p>Override the non-TTY rendering mode. Used in examples to test non-interactive output modes.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td><code>auto</code>, <code>tty</code>, <code>line-by-line</code>, <code>static</code>, <code>plain</code></td></tr><tr><td><strong>Default</strong></td><td><code>auto</code></td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_NONTTY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plain</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/inline/inline-nontty.tsx</span></span></code></pre></div><h3 id="silvery-theme" tabindex="-1">SILVERY_THEME <a class="header-anchor" href="#silvery-theme" aria-label="Permalink to &quot;SILVERY_THEME&quot;">​</a></h3><p>Override the color theme by name. Used by the examples viewer to switch palettes.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Values</strong></td><td>Any built-in palette name (e.g. <code>catppuccin-mocha</code>, <code>dracula</code>, <code>tokyo-night</code>)</td></tr><tr><td><strong>Default</strong></td><td>Auto-detected from terminal</td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SILVERY_THEME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">catppuccin-mocha</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/banner.tsx</span></span></code></pre></div><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th><th>Category</th></tr></thead><tbody><tr><td><code>SILVERY_STRICT</code></td><td>Incremental vs fresh <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> check</td><td>Verification</td></tr><tr><td><code>SILVERY_STRICT_TERMINAL</code></td><td>ANSI output via terminal emulators</td><td>Verification</td></tr><tr><td><code>SILVERY_STRICT_ACCUMULATE</code></td><td>Replay all frames (O(N^2))</td><td>Verification</td></tr><tr><td><code>SILVERY_STABILITY_SKIP_LINES</code></td><td>Skip lines in stability checks</td><td>Verification</td></tr><tr><td><code>SILVERY_INSTRUMENT</code></td><td>Render pipeline stats</td><td>Debugging</td></tr><tr><td><code>SILVERY_CELL_DEBUG</code></td><td>Per-cell <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> trace</td><td>Debugging</td></tr><tr><td><code>SILVERY_CAPTURE_OUTPUT</code></td><td>Capture ANSI frames to file</td><td>Debugging</td></tr><tr><td><code>SILVERY_CAPTURE_RAW</code></td><td>Capture raw diff patches to file</td><td>Debugging</td></tr><tr><td><code>SILVERY_DEV</code></td><td>Dev inspector</td><td>Debugging</td></tr><tr><td><code>SILVERY_DEV_LOG</code></td><td>Dev inspector log file</td><td>Debugging</td></tr><tr><td><code>SILVERY_ENGINE</code></td><td>Layout engine selection</td><td>Configuration</td></tr><tr><td><code>SILVERY_SYNC_UPDATE</code></td><td>Synchronized terminal output</td><td>Configuration</td></tr><tr><td><code>SILVERY_BG_CONFLICT</code></td><td>Background conflict handling</td><td>Configuration</td></tr><tr><td><code>SILVERY_NO_INCREMENTAL</code></td><td>Disable <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span></td><td>Configuration</td></tr><tr><td><code>SILVERY_NO_TEXT_CACHE</code></td><td>Disable text measurement cache</td><td>Configuration</td></tr><tr><td><code>SILVERY_NONTTY</code></td><td>Non-TTY rendering mode</td><td>Configuration</td></tr><tr><td><code>SILVERY_THEME</code></td><td>Theme override</td><td>Configuration</td></tr></tbody></table>`,91)])])}const k=e(n,[["render",r]]);export{g as __pageData,k as default};
